class Solution:
    def __init__(self):
        self.memoized_value = None
    def memoized_component(self, props):
        if self.memoized_value is None or self._should_recalculate(props):
            self.memoized_value = props.a + props.b
        return self.memoized_value
    def _should_recalculate(self, props):
        return JSON.stringify(props) !== JSON.stringify({ 'a': props['a'], 'b': props['b'], 'c': props['c'] })
